change_1.comment:
// CATALOG_TOTAL = wins.length (full review catalog including collision sub-claims).
// COLLISION_COUNT = wins.length - baseWins.length (rows whose id has a letter suffix).
// TOTAL_WINS stays as baseWins.length — dome's claimed count.
// Use CATALOG_TOTAL anywhere a verdict tally is the numerator (since the tally
// is computed over all 72 catalog rows); use TOTAL_WINS for prose about what
// the dome claims as its own count.

change_2.insert:
const collisionWins = wins.filter(w => /^\d{3}[a-z]$/i.test(w.id));
// catalogTotal === wins.length; we derive it via baseWins + collisionWins for the
// build-time sanity check below.

change_2.build_invariant:
// SANITY: baseWins.length + collisionWins.length must equal wins.length.
// If not, the regex above missed a row shape (e.g. four-digit ID, two-letter suffix)
// — fail the build so a future schema change does not silently corrupt the
// CATALOG_TOTAL caption math.
if (baseWins.length + collisionWins.length !== wins.length) {
  throw new Error(`build: ID-shape coverage gap — baseWins=${baseWins.length} + collisions=${collisionWins.length} != wins.length=${wins.length}`);
}
